这是一个经典的快速排序实现，包含原地分区和随机 pivot：

```javascript
/**
 * 快速排序 - 原地分区版本（节省内存）
 * @param {number[]} arr - 待排序数组
 * @param {number} left - 左边界（默认 0）
 * @param {number} right - 右边界（默认 arr.length - 1）
 * @returns {number[]} 排序后的数组（原地修改并返回）
 */
function quickSort(arr, left = 0, right = arr.length - 1) {
  if (left >= right) return arr;

  const pivotIndex = partition(arr, left, right);
  quickSort(arr, left, pivotIndex - 1);
  quickSort(arr, pivotIndex + 1, right);

  return arr;
}

/**
 * 分区：选 pivot，把小的放左边，大的放右边
 * 使用随机 pivot 避免最坏情况 O(n²)
 */
function partition(arr, left, right) {
  // 随机选 pivot，和最后一个元素交换
  const randomIndex = left + Math.floor(Math.random() * (right - left + 1));
  [arr[randomIndex], arr[right]] = [arr[right], arr[randomIndex]];

  const pivot = arr[right];
  let i = left; // i 指向"小元素区域"的末尾

  for (let j = left; j < right; j++) {
    if (arr[j] < pivot) {
      [arr[i], arr[j]] = [arr[j], arr[i]];
      i++;
    }
  }

  // 把 pivot 放到正确位置
  [arr[i], arr[right]] = [arr[right], arr[i]];
  return i;
}

// ---- 测试 ----
const testCases = [
  [3, 1, 4, 1, 5, 9, 2, 6, 5, 3, 5],
  [5],                           // 单元素
  [],                            // 空数组
  [9, 8, 7, 6, 5],              // 逆序
  [1, 2, 3, 4, 5],              // 已排序
  [5, 2, 5, 2, 5, 2],           // 重复元素
];

for (const tc of testCases) {
  // 打印排序前（用副本避免被原地修改）
  console.log(`${JSON.stringify([...tc])} → ${JSON.stringify(quickSort(tc))}`);
}

// 性能测试
const huge = Array.from({ length: 100_000 }, () => Math.floor(Math.random() * 100000));
console.time('quickSort 10万条');
quickSort(huge);
console.timeEnd('quickSort 10万条');
```

**关键点：**

- **时间复杂度**：平均 O(n log n)，最坏 O(n²)（随机 pivot 大幅降低最坏情况概率）
- **空间复杂度**：O(log n)（递归栈深度）
- **原地排序**：直接修改原数组，不创建额外副本
- **随机 pivot**：用 `Math.random()` 避免固定选最右元素导致在已排序数组上退化

